const stocks = $input.first().json.stocks || [];
const alerts = [];

stocks.forEach(s => {
  const chg = parseFloat(s.change_pct) || 0;
  const vol = parseFloat(s.volume_ratio) || 0;

  // 异动规则：涨跌幅>5% 或 量比>3
  if (Math.abs(chg) > 5 || vol > 3) {
    alerts.push({
      code: s.code,
      name: s.name,
      change_pct: chg,
      volume_ratio: vol,
      price: s.price,
      amount: s.amount,
      alert_type: Math.abs(chg) > 5 ? '大幅波动' : '量能异动'
    });
  }
});

return alerts.map(a => ({json: a}));

const alerts = $input.all().filter(i => i.json.code).map(i => i.json);
const users = $input.all().filter(i => i.json.watchlist).map(i => i.json);

const notifications = [];
users.forEach(user => {
  const userAlerts = alerts.filter(a => 
    user.watchlist.some(w => w.symbol === a.code)
  );
  if (userAlerts.length > 0) {
    notifications.push({
      user_id: user.user_id,
      alerts: userAlerts,
      message: userAlerts.map(a => 
        `🚨 ${a.name}(${a.code}) ${a.alert_type}\n涨跌: ${a.change_pct > 0 ? '+' : ''}${a.change_pct}%\n价格: ${a.price}\n成交: ${a.amount}`
      ).join('\n\n')
    });
  }
});

return notifications.map(n => ({json: n}));
